IvParameterSpec iv = new IvParameterSpec(FIXED_IV.getBytes(StandardCharsets.UTF_8));

cipher.init(Cipher.ENCRYPT_MODE, key, iv);

return cipher.doFinal(data.getBytes(StandardCharsets.UTF_8));

}



